export const LOGICAL_OPS = ["=", "!=", ">", ">=", "<", "<="] as const;
export type LogicalOp = (typeof LOGICAL_OPS)[number];

export const compareLogicOps = (operator: LogicalOp, a: number, b: number) => {
  // prettier-ignore
  switch (operator) {
    case "=": return a === b;
    case "!=": return a !== b;
    case ">": return a > b;
    case ">=": return a >= b;
    case "<": return a < b;
    case "<=": return a <= b;
    default: return false;
  }
};

export const compareLogic = (type: "AND" | "OR", ...items: any[]) =>
  type === "AND" ? items.every(Boolean) : type === "OR" ? items.some(Boolean) : null;

export const durationRegex = /^(?:\d+h)?(?:\d+m)?(?:\d+s)?(?:\d+z)?$/;

export const durationToSeconds = (input: string) => {
  let total = 0;

  for (const [, valueStr, unit] of input.matchAll(/(\d+)([hmsz])/g)) {
    const value = Number(valueStr);

    if (unit === "h") total += value * 3600;
    else if (unit === "m") total += value * 60;
    else if (unit === "s") total += value;
    else if (unit === "z") total += value / 1000;
  }

  return total;
};

// prettier-ignore
export const fractionStringToNumber = (str: string) => str.split("/").map((s) => +s).reduce((a, b) => a / b);

export const logicOpsToMongo = (op: LogicalOp | "") => {
  // prettier-ignore
  switch (op) {
    case "=": return "$eq";
    case "!=": return "$ne";
    case ">": return "$gt";
    case ">=": return "$gte";
    case "<": return "$lt";
    case "<=": return "$lte";
    default: return null;
  }
};

export const round = (num: number, decimals = 2) => {
  const n = Math.pow(10, decimals);
  return Math.round((num + Number.EPSILON) * n) / n;
};

export const secondsToDuration = (input: number) => {
  const hours = Math.floor(input / 3600);
  const minutes = Math.floor((input % 3600) / 60);
  const seconds = Math.floor(input % 60);
  const milliseconds = Math.round((input % 1) * 1000);

  return (
    [
      hours > 0 ? `${hours}h` : "",
      minutes > 0 ? `${minutes}m` : "",
      seconds > 0 ? `${seconds}s` : "",
      milliseconds > 0 ? `${milliseconds}z` : "",
    ]
      .filter(Boolean)
      .join("") || "0s"
  );
};
